/**
 * API Route: Get Grouped Pages
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export const dynamic = 'force-dynamic';
export const revalidate = 0;

export async function GET(request: NextRequest) {
  try {
    console.log('Fetching grouped pages...');
    
    const groups = await prisma.pageGroup.findMany({
      include: {
        pages: {
          orderBy: [
            { isDefaultLang: 'desc' },
            { language: 'asc' }
          ],
          select: {
            id: true,
            title: true,
            slug: true,
            language: true,
            status: true,
            isDefaultLang: true,
            lastSyncedAt: true,
            updatedAt: true,
            createdAt: true
          }
        }
      },
      orderBy: { name: 'asc' }
    });

    const ungroupedPages = await prisma.page.findMany({
      where: { pageGroupId: null },
      orderBy: { title: 'asc' },
      select: {
        id: true,
        title: true,
        slug: true,
        language: true,
        status: true,
        isDefaultLang: true,
        updatedAt: true,
        createdAt: true
      }
    });

    console.log('Fetched:', {
      groups: groups.length,
      totalPagesInGroups: groups.reduce((sum, g) => sum + g.pages.length, 0),
      ungroupedPages: ungroupedPages.length
    });

    const stats = {
      totalGroups: groups.length,
      totalPages: groups.reduce((sum, g) => sum + g.pages.length, 0) + ungroupedPages.length,
      ungroupedPages: ungroupedPages.length,
      languages: Array.from(
        new Set([
          ...groups.flatMap(g => g.pages.map(p => p.language)),
          ...ungroupedPages.map(p => p.language)
        ])
      )
    };

    return NextResponse.json({
      success: true,
      data: {
        groups,
        ungroupedPages,
        stats
      }
    });

  } catch (error) {
    console.error('Error fetching grouped pages:', error);
    return NextResponse.json(
      { 
        success: false,
        error: 'Failed to fetch pages',
        message: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    );
  }
}
